CREATE TABLE parts(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),organization_id uuid NOT NULL REFERENCES organizations(id),sku text NOT NULL,name text NOT NULL,unit_cost_cents integer NOT NULL,sale_price_cents integer NOT NULL,reorder_point numeric NOT NULL,reorder_quantity numeric NOT NULL,active boolean NOT NULL,created_at timestamptz NOT NULL,UNIQUE(tenant_id,organization_id,sku));
CREATE TABLE stock_positions(tenant_id uuid NOT NULL REFERENCES tenants(id),site_id uuid NOT NULL REFERENCES sites(id),part_id uuid NOT NULL REFERENCES parts(id),on_hand numeric NOT NULL,reserved numeric NOT NULL,updated_at timestamptz NOT NULL,PRIMARY KEY(tenant_id,site_id,part_id),CHECK(on_hand>=0 AND reserved>=0 AND reserved<=on_hand));
CREATE TABLE stock_reservations(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),site_id uuid NOT NULL REFERENCES sites(id),part_id uuid NOT NULL REFERENCES parts(id),work_order_id uuid NOT NULL REFERENCES work_orders(id),quantity numeric NOT NULL CHECK(quantity>0),status text NOT NULL CHECK(status IN('reserved','consumed','released')),created_at timestamptz NOT NULL);
CREATE TABLE purchase_orders(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),organization_id uuid NOT NULL REFERENCES organizations(id),site_id uuid NOT NULL REFERENCES sites(id),supplier_id uuid NOT NULL,number text NOT NULL,lines jsonb NOT NULL,status text NOT NULL,created_at timestamptz NOT NULL,UNIQUE(tenant_id,organization_id,number));
CREATE TABLE purchase_sequences(tenant_id uuid NOT NULL REFERENCES tenants(id),organization_id uuid NOT NULL REFERENCES organizations(id),year integer NOT NULL,value integer NOT NULL,PRIMARY KEY(tenant_id,organization_id,year));
DO $$ DECLARE n text;BEGIN FOREACH n IN ARRAY ARRAY['parts','stock_positions','stock_reservations','purchase_orders','purchase_sequences'] LOOP EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY',n);EXECUTE format('ALTER TABLE %I FORCE ROW LEVEL SECURITY',n);EXECUTE format('CREATE POLICY tenant_isolation ON %I USING (tenant_id=current_setting(''app.tenant_id'',true)::uuid) WITH CHECK (tenant_id=current_setting(''app.tenant_id'',true)::uuid)',n);END LOOP;END $$;
